// ❌ CURRENT — PII hardcoded in source
{ id: 1, name: 'Alice', email: 'alice@example.com' }

// ✅ RECOMMENDED — query from DB using parameterized statements
const { rows } = await db.query('SELECT id, name, email FROM users WHERE active = $1', [true]);
res.json(rows);
```

---

#### 6. **Security Logging & Monitoring Failures (OWASP A09) — No Access Logging**

There is no request logging. Security incidents (auth failures, unusual traffic) cannot be detected or audited.

```js
// ✅ RECOMMENDED — structured access logging with morgan
const morgan = require('morgan');
app.use(morgan('combined')); // Logs IP, method, path, status, response time

// For production, consider a structured logger like pino:
const pino = require('pino-http');
app.use(pino());
```

---

### 🔵 Medium Severity Findings

---

#### 7. **Information Disclosure via `/health` Endpoint**

The health endpoint leaks a server-side timestamp. While low-risk alone, it aids attackers in fingerprinting server timezone, uptime patterns, and timing correlation.

```js
// ❌ CURRENT
res.json({ status: 'ok', timestamp: new Date().toISOString() });

// ✅ RECOMMENDED — minimal disclosure
res.json({ status: 'ok' });
```

---

#### 8. **No CORS Policy**

No CORS headers are configured. Depending on deployment context, this either blocks legitimate cross-origin use or (if using a permissive default elsewhere) allows hostile origins to make credentialed requests.

```js
// ✅ RECOMMENDED — explicit allowlist
const cors = require('cors');
app.use(cors({
  origin: ['https://yourdomain.com'],
  methods: ['GET'],
  allowedHeaders: ['Authorization', 'Content-Type'],
}));
```

---

#### 9. **No Request Body Size Limit**

While there are no `POST` endpoints today, the app has no body parser or payload size limits. Adding any body-accepting route in the future will be immediately vulnerable to large-payload DoS attacks.

```js
// ✅ RECOMMENDED — add now, before POST routes are added
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));
```

---

#### 10. **No Global Error Handler**

Unhandled errors will cause Express to emit stack traces in responses, leaking implementation details.

```js
// ✅ RECOMMENDED — add a catch-all error handler at the END of all routes
app.use((err, req, res, next) => {
  console.error(err); // Log internally
  res.status(500).json({ error: 'Internal server error' }); // Never expose err.message
});
```

---

### 📦 Dependency Hygiene (OWASP A06)

Can't audit without seeing `package.json`, but run these regularly:

```bash
npm audit                  # Shows known CVEs in dependencies
npm audit fix              # Auto-fixes non-breaking issues
npx snyk test              # Deeper vulnerability + license scanning
```

---

### ✅ Recommended Hardened Baseline

Here's what a secured version of `app.js` looks like incorporating all fixes:

```js
const express = require('express');
const helmet  = require('helmet');
const cors    = require('cors');
const morgan  = require('morgan');
const rateLimit = require('express-rate-limit');
const jwt     = require('jsonwebtoken');

const app = express();

// Security headers
app.use(helmet());

// CORS — restrict to known origins
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') ?? [],
  methods: ['GET'],
}));

// Request logging
app.use(morgan('combined'));

// Body parsing with size limits
app.use(express.json({ limit: '10kb' }));

// Rate limiting
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100 }));

// Auth middleware
function requireAuth(req, res, next) {
  const token = req.headers['authorization']?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) return res.status(403).json({ error: 'Forbidden' });
    req.user = user;
    next();
  });
}

// Routes
app.get('/health', (_req, res) => {
  res.json({ status: 'ok' }); // No timestamp
});

app.get('/users', requireAuth, async (req, res, next) => {
  try {
    // Replace with real parameterized DB query
    const users = await db.query('SELECT id, name, email FROM users', []);
    res.json(users.rows);
  } catch (err) {
    next(err); // Forward to error handler
  }
});

// Global error handler — MUST be last
app.use((err, _req, res, _next) => {
  console.error(err);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(process.env.PORT ?? 3000);
module.exports = app;
```

---

